const webhookBody = $('Webhook - revise-post').item.json.body;
const post = $('Supabase - Get Post').item.json[0];
const bp   = $('Supabase - Get Brand Profile').item.json[0] || {};

const feedback = webhookBody.feedback || '';
const scope    = webhookBody.scope || 'full';

// Scope instruction
const scopeInstructions = {
  full:     'Révise entièrement le post en appliquant le feedback.',
  opening:  'Modifie UNIQUEMENT l\'accroche (première ligne). Garde le reste strictement identique.',
  closing:  'Modifie UNIQUEMENT la conclusion et le CTA. Garde le reste strictement identique.',
  tone:     'Ajuste UNIQUEMENT le ton sans changer la structure ni le contenu.',
  length:   'Ajuste UNIQUEMENT la longueur (raccourcis ou allonges). Garde le sens identique.',
  keywords: 'Intègre les mots-clés manquants naturellement. Garde la structure identique.'
};
const scopeInstruction = scopeInstructions[scope] || scopeInstructions.full;

const tone = Array.isArray(bp.tone) ? bp.tone.join(', ') : (bp.tone || 'professionnel');
const keywords = Array.isArray(bp.keywords) ? bp.keywords.join(', ') : '';
const keywordsAvoid = Array.isArray(bp.keywords_avoid) ? bp.keywords_avoid.join(', ') : '';

const systemPrompt = `Tu es un expert en rédaction LinkedIn. Tu révises un post existant selon le feedback du client.
Tu respectes scrupuleusement le profil de marque et les instructions de révision.`;

const userPrompt = `Post actuel :
${post.content}

Feedback du client :
${feedback}

Portée de la révision :
${scopeInstruction}

Profil de marque (rappel) :
- Ton : ${tone}
- Mots-clés à intégrer : ${keywords || 'aucun spécifié'}
- Mots-clés interdits : ${keywordsAvoid || 'aucun'}

Révise le post. Retourne UNIQUEMENT le texte du post révisé, sans explication ni commentaire.`;

return [{
  json: {
    systemPrompt,
    userPrompt,
    feedback,
    model: 'claude-sonnet-4-6',
    max_tokens: 1500
  }
}];

const claudeResponse = $('Claude API - Revise').item.json;
const content = claudeResponse.content?.[0]?.text || '';

if (!content) {
  throw new Error('Claude n\'a retourné aucun contenu');
}

const maxVersionData = $('Supabase - Get Max Version').item.json;
const maxVersion = Array.isArray(maxVersionData) && maxVersionData.length > 0
  ? (maxVersionData[0].version_number || 0)
  : 0;
const versionNumber = maxVersion + 1;

const postId   = $('Webhook - revise-post').item.json.body.post_id;
const feedback = $('Code - Build Revision Prompt').item.json.feedback;

return [{
  json: { content, versionNumber, postId, feedback }
}];
